<!DOCTYPE html>
<html lang="en">
<head>
<meta charset="UTF-8">
<title>Bouncing Ball Physics Playground</title>
<style>
  * { box-sizing: border-box; margin: 0; padding: 0; }
  html, body {
    height: 100%;
    background: #0d1117;
    color: #e6edf3;
    font-family: -apple-system, BlinkMacSystemFont, "Segoe UI", Roboto, sans-serif;
    display: flex;
    flex-direction: column;
    align-items: center;
    justify-content: center;
  }
  h1 {
    margin-bottom: 14px;
    font-weight: 600;
    font-size: 20px;
    letter-spacing: 0.5px;
    color: #c9d1d9;
  }
  #controls {
    margin-bottom: 14px;
    display: flex;
    gap: 10px;
  }
  button {
    background: #21262d;
    color: #e6edf3;
    border: 1px solid #30363d;
    padding: 8px 16px;
    border-radius: 6px;
    cursor: pointer;
    font-size: 14px;
    transition: background 0.15s, border-color 0.15s, transform 0.1s;
  }
  button:hover { background: #30363d; border-color: #58a6ff; }
  button:active { transform: scale(0.97); }
  #sim {
    background: #161b22;
    border: 1px solid #30363d;
    border-radius: 10px;
    box-shadow: 0 8px 32px rgba(0,0,0,0.4);
    cursor: crosshair;
    display: block;
  }
  #info {
    margin-top: 12px;
    font-size: 12px;
    color: #7d8590;
  }
</style>
</head>
<body>
  <h1>Bouncing Ball Playground</h1>
  <div id="controls">
    <button id="drop">Drop Ball</button>
    <button id="play">Pause</button>
    <button id="clear">Clear</button>
  </div>
  <canvas id="sim" width="600" height="600"></canvas>
  <div id="info">Click the canvas to add a ball. Drag from the Drop button for a toss.</div>

<script>
(function () {
  const canvas = document.getElementById('sim');
  const ctx = canvas.getContext('2d');
  const W = canvas.width;
  const H = canvas.height;

  // Physics constants
  const GRAVITY = 0.35;       // downward acceleration per step
  const RESTITUTION = 0.82;   // energy retained on bounce
  const FRICTION = 0.995;     // tangential damping per step
  const MIN_BOUNCE = 0.4;     // minimum vertical speed to keep alive

  const balls = [];
  let playing = true;
  let rafId = null;
  let lastTime = 0;

  function rand(min, max) { return Math.random() * (max - min) + min; }

  function addBall(x, y, vx = 0, vy = 0, r) {
    if (r === undefined || r === null) r = rand(10, 22);
    // Clamp into canvas so the new ball is fully in bounds
    r = Math.max(3, Math.min(r, Math.min(W, H) / 2 - 1));
    x = Math.max(r, Math.min(W - r, x));
    y = Math.max(r, Math.min(H - r, y));
    balls.push({ x, y, vx, vy, r });
  }

  function clearBalls() { balls.length = 0; }

  function step(dt) {
    // dt scales gravity slightly so behavior is reasonable across frame rates
    const gScale = Math.min(Math.max(dt / 16.67, 0.25), 3);

    for (let i = 0; i < balls.length; i++) {
      const b = balls[i];

      // Apply gravity
      b.vy += GRAVITY * gScale;

      // Integrate
      b.x += b.vx;
      b.y += b.vy;

      // Collide with walls (clamp + reverse perpendicular component)
      if (b.x - b.r < 0) {
        b.x = b.r;
        b.vx = -b.vx * RESTITUTION;
      } else if (b.x + b.r > W) {
        b.x = W - b.r;
        b.vx = -b.vx * RESTITUTION;
      }

      if (b.y - b.r < 0) {
        b.y = b.r;
        b.vy = -b.vy * RESTITUTION;
      } else if (b.y + b.r > H) {
        b.y = H - b.r;
        b.vy = -b.vy * RESTITUTION;
        b.vx *= FRICTION;
        // Prevent infinite tiny jitter on the floor
        if (Math.abs(b.vy) < MIN_BOUNCE) b.vy = 0;
      }
    }
    draw();
  }

  function draw() {
    ctx.fillStyle = '#161b22';
    ctx.fillRect(0, 0, W, H);

    // subtle grid
    ctx.strokeStyle = 'rgba(255,255,255,0.03)';
    ctx.lineWidth = 1;
    for (let x = 0; x < W; x += 40) {
      ctx.beginPath(); ctx.moveTo(x + 0.5, 0); ctx.lineTo(x + 0.5, H); ctx.stroke();
    }
    for (let y = 0; y < H; y += 40) {
      ctx.beginPath(); ctx.moveTo(0, y + 0.5); ctx.lineTo(W, y + 0.5); ctx.stroke();
    }

    for (let i = 0; i < balls.length; i++) {
      const b = balls[i];
      // Shadow / glow
      const grad = ctx.createRadialGradient(b.x, b.y, 0, b.x, b.y, b.r);
      const hue = (i * 47) % 360;
      grad.addColorStop(0, `hsla(${hue}, 90%, 70%, 1)`);
      grad.addColorStop(0.7, `hsla(${hue}, 80%, 55%, 0.95)`);
      grad.addColorStop(1, `hsla(${hue}, 70%, 35%, 0.9)`);
      ctx.fillStyle = grad;
      ctx.beginPath();
      ctx.arc(b.x, b.y, b.r, 0, Math.PI * 2);
      ctx.fill();

      // Highlight
      ctx.fillStyle = 'rgba(255,255,255,0.35)';
      ctx.beginPath();
      ctx.arc(b.x - b.r * 0.35, b.y - b.r * 0.35, b.r * 0.3, 0, Math.PI * 2);
      ctx.fill();
    }
  }

  function loop(now) {
    if (!playing) return;
    const dt = lastTime ? (now - lastTime) : 16.67;
    lastTime = now;
    step(dt);
    rafId = requestAnimationFrame(loop);
  }

  // --- Controls ---
  document.getElementById('drop').addEventListener('click', () => {
    addBall(rand(W * 0.2, W * 0.8), rand(20, H * 0.3), rand(-3, 3), rand(0, 2));
  });

  const playBtn = document.getElementById('play');
  playBtn.addEventListener('click', () => {
    playing = !playing;
    playBtn.textContent = playing ? 'Pause' : 'Play';
    if (playing) {
      lastTime = 0;
      rafId = requestAnimationFrame(loop);
    } else if (rafId) {
      cancelAnimationFrame(rafId);
    }
  });

  document.getElementById('clear').addEventListener('click', clearBalls);

  // Click canvas to add a ball at cursor
  function getPos(e) {
    const rect = canvas.getBoundingClientRect();
    const scaleX = canvas.width / rect.width;
    const scaleY = canvas.height / rect.height;
    if (e.touches && e.touches[0]) {
      return {
        x: (e.touches[0].clientX - rect.left) * scaleX,
        y: (e.touches[0].clientY - rect.top) * scaleY
      };
    }
    return {
      x: (e.clientX - rect.left) * scaleX,
      y: (e.clientY - rect.top) * scaleY
    };
  }

  canvas.addEventListener('mousedown', (e) => {
    const p = getPos(e);
    addBall(p.x, p.y, rand(-4, 4), rand(-6, 0));
  });
  canvas.addEventListener('touchstart', (e) => {
    e.preventDefault();
    const p = getPos(e);
    addBall(p.x, p.y, rand(-4, 4), rand(-6, 0));
  }, { passive: false });

  // Seed with a few balls for immediate visual interest
  addBall(W * 0.3, H * 0.2, 3, 0, 18);
  addBall(W * 0.6, H * 0.15, -2, 1, 14);
  addBall(W * 0.5, H * 0.1, 0, 0, 22);

  // Expose API
  window.sim = {
    w: W,
    h: H,
    balls: () => balls.map(b => ({ x: b.x, y: b.y, vx: b.vx, vy: b.vy, r: b.r })),
    addBall: (x, y, vx = 0, vy = 0, r) => addBall(x, y, vx, vy, r),
    clear: () => clearBalls(),
    step: (dt = 1) => step(dt)
  };

  // Start
  rafId = requestAnimationFrame(loop);
})();
</script>
</body>
</html>
